function detectRecursiveTriggers(workflow: any): boolean {
  const nodes = workflow.nodes || [];
  const triggers = nodes.filter((n: any) => n.type.includes('Trigger'));
  const aiAgents = nodes.filter((n: any) => n.type.includes('Agent'));

  return aiAgents.some((agent: any) => {
    const connections = workflow.connections?.[agent.id] || [];
    return connections.some((conn: any) => 
      conn.node.includes('HTTPRequest') &&
      triggers.some((t: any) => t.parameters.url?.includes('webhook'))
    );
  });
}

function detectUnvalidatedOutputs(workflow: any): string[] {
  const issues: string[] = [];
  const aiNodes = workflow.nodes.filter((n: any) => n.type.includes('Agent'));

  aiNodes.forEach((node: any) => {
    const connections = workflow.connections?.[node.id] || [];
    connections.forEach((conn: any) => {
      const targetNode = workflow.nodes.find((n: any) => n.id === conn.node);
      if (targetNode?.type.includes('Email') || targetNode?.type.includes('Slack')) {
        issues.push(`AI Agent ${node.name} → ${targetNode.name} missing validation`);
      }
    });
  });
  return issues;
}

function detectCredentialExposure(node: any): boolean {
  const credentialPatterns = [
    /(?i)(api[-_]?key|secret|token|password)[\s:=]+['"][^'"]+['"]/,
    /(?i)(xoxb-|sk-)[a-zA-Z0-9]+/,
    /(?i)(ak[ia][0-9]{12,})[^a-zA-Z0-9]/
  ];

  if (!node.parameters?.tools) return false;

  const tools = Array.isArray(node.parameters.tools) ? node.parameters.tools : [node.parameters.tools];
  return tools.some((tool: any) => 
    credentialPatterns.some(pattern => pattern.test(JSON.stringify(tool)))
  );
}

