import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  apiKey: process.env.VEX_API_KEY!,
  projectId: 'n8n-agent-governance'
});

// n8n webhook handler for AI Agent outputs
export async function n8nAgentGuardrail(input: any) {
  const result = await vex.guard({
    category: 'AGENT_OUTPUT',
    framework: 'n8n',
    content: input.json.aiResponse,
    context: {
      workflowId: input.json.workflowId,
      nodeId: input.json.nodeId,
      toolsCalled: input.json.tools || [],
      memoryContext: input.json.memory || []
    },
    rules: {
      toxicity: { threshold: 0.1 },
      pii: { enabled: true },
      recursion: { maxDepth: 5 },
      credentials: { scan: true }
    }
  });

  if (!result.safe) {
    throw new Error(`Vex blocked: ${result.violations.join(', ')}`);
  }

  return {
    json: {
      ...input.json,
      vexScore: result.score,
      safe: true
    }
  };
}
